public sealed class MyResourceClass : IDisposable // Compliant: has finalizer
{
    public void Dispose()
    {
        Dispose(true);
        GC.SuppressFinalize(this); // Compliant: class has destructor below
    }

    ~MyResourceClass()
    {
        Dispose(false);
    }

    private void Dispose(bool disposing)
    {
        // Cleanup
    }
}
